"""# 2.1 Revision de la confiabilidad de la información

Antes de utilizar los datos históricos de precios de acciones en el análisis, es fundamental asegurarse de que la información provenga de fuentes confiables y que refleje de manera precisa el comportamiento real del mercado. Esta sección tiene como objetivo comparar los precios de cierre de distintas acciones provenientes de dos fuentes ampliamente utilizadas —Investing y Yahoo Finance— con el fin de evaluar la consistencia entre ellas y determinar si existen diferencias significativas que pudieran impactar los resultados del análisis posterior.
"""

# ========= Cargar archivos de Investing =========

# Funcion auxuliar para cargar csv, homologando columnas y corrigiendo tipo de fecha
def cargar_csv_investing(path, nombre_var):
    df = pd.read_csv(path)
    df.columns = [col.strip() for col in df.columns]

    # Renombrar columnas en español a inglés para homologar
    renombres = {'Fecha': 'Date','Cierre': 'Close'}
    df = df.rename(columns=renombres)

    df['Date'] = pd.to_datetime(df['Date'], dayfirst=True, errors='coerce')
    df = df.sort_values('Date').reset_index(drop=True)
    globals()[f'investing_{nombre_var}'] = df[['Date', 'Close']]
    return globals()[f'investing_{nombre_var}']

# Cargar 4 archivos con precios de cada accion
inv_apple = cargar_csv_investing('/Datos históricos AAPL (1).csv', 'apple')
inv_msft = cargar_csv_investing('/Datos históricos MSFT (1).csv', 'msft')
inv_google = cargar_csv_investing('/Datos históricos GOOGL (1).csv', 'google')
inv_amazon = cargar_csv_investing('/Datos históricos AMZN (1).csv', 'amazon')

# En nuestros datos de yfinance la fecha esta como indice entonces la pasaremos a columna
def mod_yf(df):
    df_copy = df.copy()
    df_copy.index = pd.to_datetime(df_copy.index)
    if df_copy.index.tz is not None:
        df_copy.index = df_copy.index.tz_localize(None)
    df_copy = df_copy.reset_index()

    fecha_col = None
    for col in df_copy.columns:
        if pd.api.types.is_datetime64_any_dtype(df_copy[col]):
            fecha_col = col
            break

    df_copy = df_copy.rename(columns={fecha_col: 'Date'})
    return df_copy[['Date', 'Close']]

def comparar_diferencias(df_investing, df_base, nombre, umbral=1.0):
    df_base_tmp = mod_yf(df_base)

    comparacion = pd.merge(
        df_investing,
        df_base_tmp,
        on='Date',
        suffixes=('_investing', '_base')
    )

    # Veremos la diferencia porcentual ya que queremos comparar qué tanto difieren proporcionalmente los precios entre las dos fuentes
    comparacion['Diferencia'] = (comparacion['Close_investing'] - comparacion['Close_base']) / comparacion['Close_base'] * 100

    # Estadísticas
    media = comparacion['Diferencia'].mean()
    std = comparacion['Diferencia'].std()
    max_dif = comparacion['Diferencia'].max()
    min_dif = comparacion['Diferencia'].min()

    print(f"\n{nombre.upper()}:")
    print(f"Diferencia media porcentual: {media:.4f}%")
    print(f"Desviación estándar: {std:.4f}%")
    print(f"Diferencia máxima: {max_dif:.4f}%")
    print(f"Diferencia mínima: {min_dif:.4f}%")

    dentro_rango = comparacion['Diferencia'].abs().le(umbral).mean() * 100
    print(f"{dentro_rango:.2f}% de los días tienen diferencia dentro de ±{umbral}%")

    # ====== Gráfica de precios ======
    plt.figure(figsize=(12, 5))
    plt.plot(comparacion['Date'], comparacion['Close_investing'], label='Investing', alpha=0.7)
    plt.plot(comparacion['Date'], comparacion['Close_base'], label='Yahoo Finance', alpha=0.7)
    plt.title(f'Precios de cierre - {nombre.upper()}')
    plt.xlabel('Fecha')
    plt.ylabel('Precio de cierre')
    plt.legend()
    plt.grid(True)
    plt.tight_layout()
    plt.show()

    # ====== Gráfica de diferencia ======
    plt.figure(figsize=(12, 4))
    plt.plot(comparacion['Date'], comparacion['Diferencia'], color='purple', label='Diferencia % (Investing - Yahoo Finance)')
    plt.axhline(umbral, color='red', linestyle='--', linewidth=1, label=f'±{umbral}%')
    plt.axhline(-umbral, color='red', linestyle='--', linewidth=1)
    plt.title(f'Diferencia porcentual diaria - {nombre.upper()}')
    plt.xlabel('Fecha')
    plt.ylabel('Diferencia porcentual (%)')
    plt.legend()
    plt.grid(True)
    plt.tight_layout()
    plt.show()

# Ejecutar para cada acción con un umbral de diferencia aceptable
comparar_diferencias(inv_apple, data_apple, 'apple', umbral=1.0)
comparar_diferencias(inv_msft, data_msft, 'msft', umbral=1.0)
comparar_diferencias(inv_google, data_google, 'google', umbral=1.0)
comparar_diferencias(inv_amazon, data_amazon, 'amazon', umbral=1.0)

