"""## 3.6 ¿Cuánto valor ponemos en riesgo al invertir en una acción en particular?
Hay muchas formas de cuantificar el riesgo, una de las formas más básicas de utilizar la información que hemos recopilado sobre los rendimientos porcentuales diarios es comparando el rendimiento esperado con la desviación estándar de los rendimientos diarios.
"""

rendimientos = rendimiento_diario.dropna()

# Área constante para los puntos
area = np.pi * 20

plt.figure(figsize=(10, 8))

# Recorremos cada acción con su color personalizado
for _, nombre, color in datos:
    # Extraemos rendimiento medio y riesgo (desviación estándar) para cada acción
    x = rendimientos[nombre].mean()
    y = rendimientos[nombre].std()

    # Dibujamos el punto con su color
    plt.scatter(x, y, s=area, color=color)

    # Añadimos la etiqueta con una flecha
    plt.annotate(
        nombre,
        xy=(x, y),
        xytext=(50, 50),
        textcoords='offset points',
        ha='right',
        va='bottom',
        arrowprops=dict(arrowstyle='-', color=color, connectionstyle='arc3,rad=-0.3')
    )

