# Función para calcular el RSI (Relative Strength Index)
def calcular_rsi(precios, ventana=14):
    delta = precios.diff()
    ganancias = delta.clip(lower=0)
    perdidas = -delta.clip(upper=0)
    avg_ganancia = ganancias.rolling(ventana).mean()
    avg_perdida = perdidas.rolling(ventana).mean()
    rs = avg_ganancia / avg_perdida
    return 100 - (100 / (1 + rs))

# Preparación de las acciones
def preparar_datos(accion):
    df = pd.read_csv("precios_acciones_limpios.csv", parse_dates=['Date'], index_col='Date')[[accion]]
    df.columns = ['Close']
    df['MA_7'] = df['Close'].rolling(7).mean()
    df['MA_21'] = df['Close'].rolling(21).mean()
    df['RSI'] = calcular_rsi(df['Close'])
    return df.dropna()

