    modelo = XGBRegressor(n_estimators=100)
    modelo.fit(X.iloc[:-30], y.iloc[:-30]) # Entrenamiento excluyendo los últimos 30 días


    pred = modelo.predict(X.iloc[-30:]) # Entrenamiento de los últimos 30 días
    return pred [-30:]

