# Entrenamiento del modelo LSTM
def entrenar_lstm(df, accion, lookback=20, epochs=50):
    # Extraemos las columnas de entrada que serán usadas (Precio de cierre, media móil de 7 y 21 días, RSI)
    features = df[['Close', 'MA_7', 'MA_21', 'RSI']].values
    # Se aplica el escalado MinMax para que la LSTM converja correctamente
    scaler = MinMaxScaler()
    scaled = scaler.fit_transform(features)
    # Definimos el tamaño del conjunto de entrenamiento (80% total 20% prueba)
    train_size = int(len(scaled) * 0.8)
    train = scaled[:train_size] # Conjunto de entrenamiento
    test = scaled[train_size - lookback:] # Conjunto de prueba

    # FUnción auxiliar que convierte la serie temporal en secuencias para LSTM
    def create_seq(data):
        X, y = [], []
        for i in range(lookback, len(data)):
            # Cada muestra X es una secuenci de "lookback" días
            X.append(data[i - lookback:i])
            # La salida y es el precio de cierre del día siguiente a la secuencia
            y.append(data[i, 0])
        return np.array(X), np.array(y)

    # Se crean las secuencias para entrenmiento y prueba
    X_train, y_train = create_seq(train)
    X_test, y_test = create_seq(test)

    # Red neuronal con dos capas LSTM y Dropout para evitar sobreajuste
    model = Sequential([
        LSTM(64, return_sequences=True, input_shape=(lookback, X_train.shape[2])),
        Dropout(0.2),
        LSTM(32),
        Dropout(0.2),
        Dense(1)
    ])

    # Compila con optimizador Adam y pérdida MSE (error cuadrático medio)
    model.compile(optimizer='adam', loss='mse')
    es = EarlyStopping(monitor='val_loss', patience=10, restore_best_weights=True)
    model.fit(X_train, y_train, epochs=epochs, batch_size=32, validation_split=0.1, callbacks=[es], verbose=0)

    # Realiza la predicción sobre el conjunto de prueba
    pred_scaled = model.predict(X_test)
    pred = scaler.inverse_transform(np.concatenate([pred_scaled, test[lookback:, 1:]], axis=1))[:, 0]
    return pred[-30:]

# Creamos un diccionario vacío
pred_lstms = {}
for accion, df in acciones_dict.items():
    pred = entrenar_lstm(df, accion) # Para cada acción llamamos a la función "Entrenar LSTM"
    pred_lstms[accion] = pred
    graficar_pred_modelo(df, pred, accion, modelo="LSTM") # Llamamos a la función para graficar

