# Entrenamiento del modelo Random Forest
def entrenar_random_forest(df, accion):#  función que entrenará un modelo Random Forest
    X = df[['MA_7', 'MA_21', 'RSI']]#Selección de variables predictoras: medias móviles de 7 y 21 días, y RSI
    y = df['Close'].shift(-1)#precio de cierre del día siguient
    df_model = pd.concat([X, y.rename("target")], axis=1).dropna() # Combinación de features y target en un nuevo DataFrame, eliminando NaN
    X = df_model[['MA_7', 'MA_21', 'RSI']]#  X con datos limpios (sin NaN)
    y = df_model['target']# Y con datos limpios

    # Configuración del modelo
    modelo = RandomForestRegressor(
        n_estimators=200,       # Número de árboles
        max_depth=7,            # Profundidad controlada para evitar overfitting
        min_samples_split=10,   # Mínimo de muestras para dividir un nodo
        min_samples_leaf=5,     # Mínimo de muestras en hojas
        max_features='sqrt',    # Features consideradas en cada división
        random_state=42,        # Para reproducibilidad
        n_jobs=-1              # Usa todos los cores del CPU
    )

    # Entrenamiento (excluyendo últimos 30 días como en tu enfoque)
    modelo.fit(X.iloc[:-30], y.iloc[:-30])

    # Predicción para los últimos 30 días
    pred = modelo.predict(X.iloc[-30:])
    return pred

# Creamos un diccionario para guardar predicciones de Random Forest
pred_rfs = {}
for accion, df in acciones_dict.items(): # Itera sobre cada acción y su DataFrame en el diccionario acciones_dict
    pred = entrenar_random_forest(df, accion)  # Entrena un modelo Random Forest y obtiene predicciones
    pred_rfs[accion] = pred # Guarda las predicciones en el diccionario usando la acción como clave
    graficar_pred_modelo(df, pred, accion, modelo="Random Forest")  ## Graficamos la random forest por acción

